import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface SpeedData {
  currentSpeeds: {
    download: number;
    upload: number;
    ping: number;
  };
  speedTrend: {
    download: number[];
    upload: number[];
  };
}

export default function Widget() {
  const data = response.data as SpeedData;
  const { currentSpeeds, speedTrend } = data;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: 'rgba(13, 71, 161, 0.7)', backdropFilter: 'blur(8px)', color: '#ffffff' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ mb: 1, color: '#00ACC1' }}>
              Network Speed Monitor
            </Typography>
            <Typography variant="body2">
              Download: {currentSpeeds.download} Mbps
            </Typography>
            <Typography variant="body2">
              Upload: {currentSpeeds.upload} Mbps
            </Typography>
            <Typography variant="body2">
              Ping: {currentSpeeds.ping} ms
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: speedTrend.download,
                  color: '#00ACC1',
                  label: 'Download Speed',
                  curve: 'natural',
                },
                {
                  type: 'line',
                  data: speedTrend.upload,
                  color: '#FF8F00',
                  label: 'Upload Speed',
                  curve: 'natural',
                },
              ]}
              xAxis={[
                {
                  data: speedTrend.download.map((_, i) => i),
                  id: 'time',
                  hide: false,
                },
              ]}
              yAxis={[{ id: 'speed' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="time"
                tickLabelStyle={{ fontSize: 10, fill: '#ffffff' }}
              />
              <ChartsYAxis
                axisId="speed"
                tickLabelStyle={{ fontSize: 10, fill: '#ffffff' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
